+      email: 'alice@example.com',
+      role: 'member',
+      createdAt: new Date(),
+      updatedAt: new Date(),
+    },
+    timestamp: new Date(),
+    ...overrides,
+  };
+}
+
+function makeStatusChangedEvent(
+  previousStatus: string,
+  newStatus: string,
+): OrderStatusChangedEvent {
+  return {
+    type: 'order:status-changed',
+    order: {
+      id: 'order-0001',
+      userId: 'user-0001',
+      items: [{ productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 }],
+      total: 20,
+      status: newStatus as 'confirmed',
+      createdAt: new Date(),
+      updatedAt: new Date(),
+    },
+    previousStatus,
+    newStatus,
+    timestamp: new Date(),
+  };
+}
+
+describe('EmailNotificationHandler', () => {
+  let eventBus: EventBus;
+  let handler: EmailNotificationHandler;
+
+  beforeEach(() => {
+    eventBus = new EventBus();
+    handler = new EmailNotificationHandler(eventBus);
+  });
+
+  describe('order:created emails', () => {
+    it('should send a confirmation email when an order is created', async () => {
+      await eventBus.emit(makeOrderCreatedEvent());
+
+      const emails = handler.getSentEmails();
+      expect(emails).toHaveLength(1);
+      expect(emails[0]?.to).toBe('alice@example.com');
+      expect(emails[0]?.subject).toContain('Order Confirmation');
+      expect(emails[0]?.subject).toContain('order-0001');
+    });
+
+    it('should include item details in the HTML body', async () => {
+      const event = makeOrderCreatedEvent({
+        order: {
+          id: 'order-0001',
+          userId: 'user-0001',
+          items: [
+            { productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 },
+            { productId: 'p2', name: 'Gadget', quantity: 1, unitPrice: 25 },
+          ],
+          total: 45,
+          status: 'pending',
+          createdAt: new Date(),
+          updatedAt: new Date(),
+        },
+      });
+
+      await eventBus.emit(event);
+
+      const email = handler.getSentEmails()[0]!;
+      expect(email.htmlBody).toContain('Widget');
+      expect(email.htmlBody).toContain('Gadget');
+      expect(email.htmlBody).toContain('$45.00');
+    });
+
+    it('should include item details in the text body', async () => {
+      await eventBus.emit(makeOrderCreatedEvent());
+
+      const email = handler.getSentEmails()[0]!;
+      expect(email.textBody).toContain('Widget x2');
+      expect(email.textBody).toContain('$20.00');
+      expect(email.textBody).toContain('Hi Alice');
+    });
+
+    it('should include the user name in the email', async () => {
+      await eventBus.emit(makeOrderCreatedEvent());
+
+      const email = handler.getSentEmails()[0]!;
+      expect(email.htmlBody).toContain('Hi Alice');
+    });
+  });
+
+  describe('order:status-changed emails', () => {
+    it('should send an email when order status changes to confirmed', async () => {
+      await eventBus.emit(makeStatusChangedEvent('pending', 'confirmed'));
+
+      const emails = handler.getSentEmails();
+      expect(emails).toHaveLength(1);
+      expect(emails[0]?.subject).toContain('Confirmed');
+      expect(emails[0]?.subject).toContain('order-0001');
+      expect(emails[0]?.htmlBody).toContain('confirmed and is being prepared');
+    });
+
+    it('should send an email when order status changes to shipped', async () => {
+      await eventBus.emit(makeStatusChangedEvent('confirmed', 'shipped'));
+
+      const email = handler.getSentEmails()[0]!;
+      expect(email.subject).toContain('Shipped');
+      expect(email.htmlBody).toContain('shipped and is on its way');
+    });
+
+    it('should send an email when order status changes to delivered', async () => {
+      await eventBus.emit(makeStatusChangedEvent('shipped', 'delivered'));
+
+      const email = handler.getSentEmails()[0]!;
+      expect(email.subject).toContain('Delivered');
+      expect(email.htmlBody).toContain('delivered');
+      expect(email.textBody).toContain('Thank you for your purchase');
+    });
+
+    it('should send an email when order is cancelled', async () => {
+      await eventBus.emit(makeStatusChangedEvent('pending', 'cancelled'));
+
+      const email = handler.getSentEmails()[0]!;
+      expect(email.subject).toContain('Cancelled');
+      expect(email.htmlBody).toContain('cancelled');
+    });
+
+    it('should send email to the order userId', async () => {
+      await eventBus.emit(makeStatusChangedEvent('pending', 'confirmed'));
+
+      expect(handler.getSentEmails()[0]?.to).toBe('user-0001');
+    });
+  });
+
+  describe('email management', () => {
+    it('should count emails', async () => {
+      expect(handler.getEmailCount()).toBe(0);
+
+      await eventBus.emit(makeStatusChangedEvent('pending', 'confirmed'));
+      expect(handler.getEmailCount()).toBe(1);
+
+      await eventBus.emit(makeStatusChangedEvent('confirmed', 'shipped'));
+      expect(handler.getEmailCount()).toBe(2);
+    });
+
+    it('should filter emails by recipient', async () => {
+      await eventBus.emit(makeOrderCreatedEvent());
+
+      expect(handler.getEmailsForRecipient('alice@example.com')).toHaveLength(1);
+      expect(handler.getEmailsForRecipient('bob@example.com')).toHaveLength(0);
+    });
+
+    it('should clear emails', async () => {
+      await eventBus.emit(makeStatusChangedEvent('pending', 'confirmed'));
+      expect(handler.getEmailCount()).toBe(1);
+
+      handler.clearEmails();
+      expect(handler.getEmailCount()).toBe(0);
+    });
+  });
+
+  describe('integration with NotificationService', () => {
+    it('should work alongside NotificationService on the same EventBus', async () => {
+      // Both handlers subscribe to the same EventBus
+      const { NotificationService } = await import(
+        '../../src/services/notification.service.js'
+      );
+      const notificationService = new NotificationService(eventBus);
+
+      await eventBus.emit(makeStatusChangedEvent('pending', 'confirmed'));
+
+      // Both services should have processed the event
+      expect(handler.getEmailCount()).toBe(1);
+      expect(notificationService.getNotificationCount()).toBe(1);
+    });
+
+    it('should handle multiple status transitions in sequence', async () => {
+      await eventBus.emit(makeStatusChangedEvent('pending', 'confirmed'));
+      await eventBus.emit(makeStatusChangedEvent('confirmed', 'shipped'));
+      await eventBus.emit(makeStatusChangedEvent('shipped', 'delivered'));
+
+      const emails = handler.getSentEmails();
+      expect(emails).toHaveLength(3);
+      expect(emails[0]?.subject).toContain('Confirmed');
+      expect(emails[1]?.subject).toContain('Shipped');
+      expect(emails[2]?.subject).toContain('Delivered');
+    });
+  });
+
+  describe('email content format', () => {
+    it('should include both HTML and text body', async () => {
+      await eventBus.emit(makeOrderCreatedEvent());
+
+      const email = handler.getSentEmails()[0]!;
+      expect(email.htmlBody).toContain('<h1>');
+      expect(email.textBody).not.toContain('<h1>');
+    });
+
+    it('should record sentAt timestamp', async () => {
+      const before = new Date();
+      await eventBus.emit(makeOrderCreatedEvent());
+      const after = new Date();
+
+      const email = handler.getSentEmails()[0]!;
+      expect(email.sentAt.getTime()).toBeGreaterThanOrEqual(before.getTime());
+      expect(email.sentAt.getTime()).toBeLessThanOrEqual(after.getTime());
+    });
+  });
+});

