/**
 * Email notification handler for order lifecycle events.
 *
 * Subscribes to order events via EventBus and formats email-specific
 * notifications with rich content (HTML-like templates, status-specific
 * messaging). Integrates with the existing NotificationService by
 * following the same EventBus subscription pattern.
 *
 * Depends on:
 * - EventBus (event system) for receiving order events
 */

import type { EventBus } from '../events/event-bus.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../events/event-types.js';
import type { OrderStatus } from '../models/order.js';
import { Logger } from '../utils/logger.js';

export interface EmailMessage {
  to: string;
  subject: string;
  htmlBody: string;
  textBody: string;
  sentAt: Date;
}

const STATUS_LABELS: Record<OrderStatus, string> = {
  pending: 'Pending',
  confirmed: 'Confirmed',
  shipped: 'Shipped',
  delivered: 'Delivered',
  cancelled: 'Cancelled',
};

const STATUS_DESCRIPTIONS: Record<OrderStatus, string> = {
  pending: 'Your order has been received and is awaiting confirmation.',
  confirmed: 'Your order has been confirmed and is being prepared.',
  shipped: 'Your order has been shipped and is on its way.',
  delivered: 'Your order has been delivered. Thank you for your purchase!',
  cancelled: 'Your order has been cancelled.',
};

export class EmailNotificationHandler {
  private logger = new Logger('EmailNotificationHandler');
  private sentEmails: EmailMessage[] = [];

  constructor(private eventBus: EventBus) {
    this.registerHandlers();
  }

  /**
   * Register event handlers via EventBus — same pattern as NotificationService.
   */
  private registerHandlers(): void {
    this.eventBus.on<OrderCreatedEvent>('order:created', (event) => {
      this.handleOrderCreated(event);
    });

    this.eventBus.on<OrderStatusChangedEvent>('order:status-changed', (event) => {
      this.handleOrderStatusChanged(event);
    });
  }

  /**
   * Handle order created — send a confirmation email with order details.
   */
  private handleOrderCreated(event: OrderCreatedEvent): void {
    this.logger.info(`Sending order confirmation email for ${event.order.id}`);

    const itemRows = event.order.items
      .map(
        (item) =>
          `<tr><td>${item.name}</td><td>${item.quantity}</td><td>$${item.unitPrice.toFixed(2)}</td><td>$${(item.quantity * item.unitPrice).toFixed(2)}</td></tr>`,
      )
      .join('');

    const itemList = event.order.items
      .map((item) => `- ${item.name} x${item.quantity} @ $${item.unitPrice.toFixed(2)}`)
      .join('\n');

    const htmlBody = `<h1>Order Confirmation</h1>
<p>Hi ${event.user.name},</p>
<p>Thank you for your order! Here are the details:</p>
<p><strong>Order ID:</strong> ${event.order.id}</p>
<table>
<tr><th>Item</th><th>Qty</th><th>Price</th><th>Subtotal</th></tr>
${itemRows}
</table>
<p><strong>Total: $${event.order.total.toFixed(2)}</strong></p>
<p>${STATUS_DESCRIPTIONS.pending}</p>`;

    const textBody = `Order Confirmation

Hi ${event.user.name},

Thank you for your order! Here are the details:

Order ID: ${event.order.id}
${itemList}

Total: $${event.order.total.toFixed(2)}

${STATUS_DESCRIPTIONS.pending}`;

    this.sendEmail({
      to: event.user.email,
      subject: `Order Confirmation - ${event.order.id}`,
      htmlBody,
      textBody,
    });
  }

  /**
   * Handle order status change — send a status update email.
   */
  private handleOrderStatusChanged(event: OrderStatusChangedEvent): void {
    const newStatus = event.newStatus as OrderStatus;
    this.logger.info(
      `Sending status update email for ${event.order.id}: ${event.previousStatus} -> ${newStatus}`,
    );

    const statusLabel = STATUS_LABELS[newStatus] ?? newStatus;
    const statusDescription = STATUS_DESCRIPTIONS[newStatus] ?? '';

    const htmlBody = `<h1>Order Status Update</h1>
<p>Your order <strong>${event.order.id}</strong> has been updated.</p>
<p><strong>New Status:</strong> ${statusLabel}</p>
<p>${statusDescription}</p>`;

    const textBody = `Order Status Update

Your order ${event.order.id} has been updated.

New Status: ${statusLabel}

${statusDescription}`;

    this.sendEmail({
      to: event.order.userId,
      subject: `Order ${statusLabel} - ${event.order.id}`,
      htmlBody,
      textBody,
    });
  }

  /**
   * Send an email (in-memory for this demo, would integrate with SMTP/API in production).
   */
  private sendEmail(params: Omit<EmailMessage, 'sentAt'>): void {
    const email: EmailMessage = {
      ...params,
      sentAt: new Date(),
    };
    this.sentEmails.push(email);
    this.logger.info(`Email sent to ${params.to}: ${params.subject}`);
  }

  /**
   * Get all sent emails.
   */
  getSentEmails(): EmailMessage[] {
    return [...this.sentEmails];
  }

  /**
   * Get sent emails for a specific recipient.
   */
  getEmailsForRecipient(recipient: string): EmailMessage[] {
    return this.sentEmails.filter((e) => e.to === recipient);
  }

  /**
   * Get the count of sent emails.
   */
  getEmailCount(): number {
    return this.sentEmails.length;
  }

  /**
   * Clear all sent emails (useful for testing).
   */
  clearEmails(): void {
    this.sentEmails = [];
  }
}

